import numpy as npfrom PySide6.QtWidgets import (    QMainWindow, QWidget, QVBoxLayout, QHBoxLayout,    QPushButton, QRadioButton, QGroupBox, QLabel,    QDoubleSpinBox, QCheckBox, QFormLayout, QGridLayout,    QButtonGroup, QSizePolicy, QFileDialog, QMessageBox,    QProgressBar)from PySide6.QtCore import Qtfrom PySide6.QtGui import QImage, QPixmapfrom gui.viewer_3d import Viewer3Dfrom data_io.mat_loader import load_phantom_matfrom data_io.mat_saver import save_sinogram_matfrom data_io.csv_saver import save_motion_sequence_csvfrom core.measurement_worker import MeasurementWorker, generate_motion_sequencefrom core.simulation_worker import SimulationWorkerclass MainWindow(QMainWindow):    def __init__(self):        super().__init__()        self.setWindowTitle("Holographic Tomograph Virtual Laboratory")        self.resize(1280, 720)        # Persistence for loaded data and workers        self.phantom_data = None        self.worker = None        self.sim_worker = None        self.motion_sequence = None                # Persistence for generated data to save/replay        self.current_sino_amp = None        self.current_sino_ph = None        self.current_rayXY = None        self.current_bg_ri = 1.5123        central_widget = QWidget()        self.setCentralWidget(central_widget)        main_layout = QHBoxLayout(central_widget)        # --- LEFT PANEL (Graphics) ---        left_panel = QWidget()        left_layout = QVBoxLayout(left_panel)        left_layout.setContentsMargins(0, 0, 0, 0)        self.group_3d = QGroupBox("3D Visualization")        layout_3d = QVBoxLayout(self.group_3d)        self.viewer_3d = Viewer3D()        layout_3d.addWidget(self.viewer_3d)        left_layout.addWidget(self.group_3d, stretch=2)        bottom_row_widget = QWidget()        bottom_row_layout = QHBoxLayout(bottom_row_widget)        bottom_row_layout.setContentsMargins(0, 0, 0, 0)        self.group_amplitude = QGroupBox("Amplitude Image")        amplitude_layout = QVBoxLayout(self.group_amplitude)        self.img_amplitude = QLabel("Waiting for data...")        self.img_amplitude.setStyleSheet("background-color: black; color: #555; border: 1px solid gray;")        self.img_amplitude.setAlignment(Qt.AlignmentFlag.AlignCenter)                # Block widget expansion        self.img_amplitude.setSizePolicy(QSizePolicy.Policy.Ignored, QSizePolicy.Policy.Ignored)        self.img_amplitude.setMinimumSize(1, 1)        self.img_amplitude.setScaledContents(False)                amplitude_layout.addWidget(self.img_amplitude)        self.group_phase = QGroupBox("Phase Image")        phase_layout = QVBoxLayout(self.group_phase)        self.img_phase = QLabel("Waiting for data...")        self.img_phase.setStyleSheet("background-color: black; color: #555; border: 1px solid gray;")        self.img_phase.setAlignment(Qt.AlignmentFlag.AlignCenter)                # Block widget expansion        self.img_phase.setSizePolicy(QSizePolicy.Policy.Ignored, QSizePolicy.Policy.Ignored)        self.img_phase.setMinimumSize(1, 1)        self.img_phase.setScaledContents(False)                phase_layout.addWidget(self.img_phase)        bottom_row_layout.addWidget(self.group_amplitude)        bottom_row_layout.addWidget(self.group_phase)        left_layout.addWidget(bottom_row_widget, stretch=1)        main_layout.addWidget(left_panel, stretch=1)        # --- RIGHT PANEL (Settings) ---        right_panel = QWidget()        right_panel.setFixedWidth(400)        right_layout = QVBoxLayout(right_panel)        self.btn_load_phantom = QPushButton("Load phantom")        self.btn_load_phantom.setMinimumHeight(40)        right_layout.addWidget(self.btn_load_phantom)        self.group_scan_mode = QGroupBox("Scan Mode")        scan_mode_layout = QVBoxLayout()        self.radio_galvo = QRadioButton("Galvo scan")        self.radio_galvo.setChecked(True)         self.radio_obj_rot = QRadioButton("Object rotation scan")        self.scan_btn_group = QButtonGroup()        self.scan_btn_group.addButton(self.radio_galvo)        self.scan_btn_group.addButton(self.radio_obj_rot)        scan_mode_layout.addWidget(self.radio_galvo)        scan_mode_layout.addWidget(self.radio_obj_rot)        self.group_scan_mode.setLayout(scan_mode_layout)        right_layout.addWidget(self.group_scan_mode)        self.group_settings = QGroupBox("Settings")        settings_layout = QFormLayout()        self.spin_azimuth = QDoubleSpinBox()        self.spin_azimuth.setRange(-360.0, 360.0)        self.spin_azimuth.setValue(45.0)        self.spin_step = QDoubleSpinBox()        self.spin_step.setRange(0.01, 360.0)        self.spin_step.setValue(10.0)        settings_layout.addRow("Beam azimuth (deg):", self.spin_azimuth)        settings_layout.addRow("Rotation step (deg):", self.spin_step)        self.group_settings.setLayout(settings_layout)        right_layout.addWidget(self.group_settings)        self.group_accuracy = QGroupBox("Computational Accuracy")        accuracy_layout = QVBoxLayout()        self.radio_interp_1 = QRadioButton("Linear (Order 1 - Fast)")        self.radio_interp_3 = QRadioButton("Cubic (Order 3 - Slow)")        self.radio_interp_1.setChecked(True)        self.interp_btn_group = QButtonGroup()        self.interp_btn_group.addButton(self.radio_interp_1)        self.interp_btn_group.addButton(self.radio_interp_3)        accuracy_layout.addWidget(self.radio_interp_1)        accuracy_layout.addWidget(self.radio_interp_3)        self.group_accuracy.setLayout(accuracy_layout)        right_layout.addWidget(self.group_accuracy)        self.group_kinematics = QGroupBox("Constant Kinematics")        kinematics_layout = QGridLayout()                self.check_k_x = QCheckBox("X radius")        self.spin_k_x = QDoubleSpinBox(); self.spin_k_x.setRange(0, 50); self.spin_k_x.setValue(5); self.spin_k_x.setEnabled(False)        self.check_k_x.toggled.connect(self.spin_k_x.setEnabled)        self.check_k_y = QCheckBox("Y radius")        self.spin_k_y = QDoubleSpinBox(); self.spin_k_y.setRange(0, 50); self.spin_k_y.setValue(5); self.spin_k_y.setEnabled(False)        self.check_k_y.toggled.connect(self.spin_k_y.setEnabled)        self.check_k_z = QCheckBox("Z fall range")        self.spin_k_z = QDoubleSpinBox(); self.spin_k_z.setRange(0, 50); self.spin_k_z.setValue(10); self.spin_k_z.setEnabled(False)        self.check_k_z.toggled.connect(self.spin_k_z.setEnabled)        kinematics_layout.addWidget(self.check_k_x, 0, 0); kinematics_layout.addWidget(self.spin_k_x, 0, 1)        kinematics_layout.addWidget(self.check_k_y, 1, 0); kinematics_layout.addWidget(self.spin_k_y, 1, 1)        kinematics_layout.addWidget(self.check_k_z, 2, 0); kinematics_layout.addWidget(self.spin_k_z, 2, 1)        self.group_kinematics.setLayout(kinematics_layout)        right_layout.addWidget(self.group_kinematics)        self.group_noise = QGroupBox("Motion Noise")        noise_layout = QGridLayout()        noise_rows = [("Translate X", 0.5), ("Translate Y", 0.5), ("Translate Z", 0.5),                      ("Quaternion X", 0.25), ("Quaternion Y", 0.25), ("Quaternion Z", 0.25)]        self.noise_controls = {}        for row_idx, (name, def_val) in enumerate(noise_rows):            cb = QCheckBox(name)            spin = QDoubleSpinBox(); spin.setRange(0, 5); spin.setValue(def_val); spin.setDecimals(3); spin.setEnabled(False)            cb.toggled.connect(spin.setEnabled)            noise_layout.addWidget(cb, row_idx, 0); noise_layout.addWidget(spin, row_idx, 1)            self.noise_controls[name] = {"checkbox": cb, "value": spin}        self.group_noise.setLayout(noise_layout)        right_layout.addWidget(self.group_noise)                # --- ACTION PANEL ---        self.btn_start_measurement = QPushButton("Start Measurement")        self.btn_start_measurement.setMinimumHeight(50)        self.btn_start_measurement.setStyleSheet("font-weight: bold; font-size: 14px;")        right_layout.addWidget(self.btn_start_measurement)        self.btn_replay_measurement = QPushButton("Replay Measurement")        self.btn_replay_measurement.setMinimumHeight(40)        self.btn_replay_measurement.setEnabled(False)        right_layout.addWidget(self.btn_replay_measurement)        self.progress_bar = QProgressBar()        self.progress_bar.setRange(0, 100)        self.progress_bar.setValue(0)        self.progress_bar.setTextVisible(True)        self.progress_bar.setVisible(False)        right_layout.addWidget(self.progress_bar)        dummy_buttons_layout = QHBoxLayout()        self.btn_save_sino = QPushButton("Save Sinogram")        self.btn_save_csv = QPushButton("Save CSV")        dummy_buttons_layout.addWidget(self.btn_save_sino)        dummy_buttons_layout.addWidget(self.btn_save_csv)        right_layout.addLayout(dummy_buttons_layout)        right_layout.addStretch()        main_layout.addWidget(right_panel)        # Signal connections        self.btn_load_phantom.clicked.connect(self.action_load_phantom)        self.spin_azimuth.valueChanged.connect(self.action_update_azimuth)        self.btn_start_measurement.clicked.connect(self.action_toggle_measurement)        self.btn_replay_measurement.clicked.connect(self.action_replay_measurement)        self.btn_save_sino.clicked.connect(self.action_save_sinogram)        self.btn_save_csv.clicked.connect(self.action_save_csv)        self.action_update_azimuth(self.spin_azimuth.value())    def action_load_phantom(self):        filepath, _ = QFileDialog.getOpenFileName(self, "Open Phantom", "", "MAT Files (*.mat)")        if filepath:            try:                self.phantom_data = load_phantom_mat(filepath)                self.viewer_3d.set_phantom_data(self.phantom_data)            except Exception as e:                QMessageBox.critical(self, "Error", str(e))    def action_update_azimuth(self, value: float):        self.viewer_3d.update_beam_transform(azimuth_deg=value, rotation_deg=0.0)            def action_toggle_measurement(self):        """        Acts as a toggle switch between starting and canceling the computation.        """        if self.sim_worker and self.sim_worker.isRunning():            self.sim_worker.stop()            self.btn_start_measurement.setText("Canceling...")            self.btn_start_measurement.setEnabled(False)        else:            self.action_start_measurement()    def action_start_measurement(self):        """        Step 1: Lock the UI, generate the motion sequence, and start calculations.        """        if self.phantom_data is None:            QMessageBox.warning(self, "Warning", "Please load a phantom first!")            return        # Disable most UI elements but keep the start button active for cancellation        self.set_ui_enabled(False)        self.btn_start_measurement.setText("Cancel Calculation")        self.btn_start_measurement.setEnabled(True)                self.progress_bar.setValue(0)        self.progress_bar.setVisible(True)        kinematics = {            'x': (self.check_k_x.isChecked(), self.spin_k_x.value()),            'y': (self.check_k_y.isChecked(), self.spin_k_y.value()),            'z': (self.check_k_z.isChecked(), self.spin_k_z.value())        }        noise = {name: (ctrl['checkbox'].isChecked(), ctrl['value'].value())                  for name, ctrl in self.noise_controls.items()}        is_galvo = self.radio_galvo.isChecked()        azimuth = self.spin_azimuth.value()        step = self.spin_step.value()        num_projs = int(360 / step)                interp_order = 1 if self.radio_interp_1.isChecked() else 3        # Generate the motion sequence outside the worker        self.motion_sequence = generate_motion_sequence(num_projs, step, is_galvo, azimuth, kinematics, noise)        # Calculate K-space trajectory for the simulation worker        radius = np.sin(np.radians(azimuth))        angles = np.linspace(0, 2 * np.pi, num_projs, endpoint=False)        rayXY = np.zeros((2, num_projs))        rayXY[0, :] = radius * np.cos(angles)        rayXY[1, :] = radius * np.sin(angles)                # Save rayXY for later saving        self.current_rayXY = rayXY        # Dynamically extract background refractive index from the phantom's corner        bg_ri = float(np.real(self.phantom_data[0, 0, 0]))        self.current_bg_ri = bg_ri        metadata = {'dx': 0.234375, 'lambda': 0.6328, 'n_immersion': bg_ri}        # Initialize and start the computation thread        self.sim_worker = SimulationWorker(            self.phantom_data, metadata, rayXY, self.motion_sequence, interp_order=interp_order        )                self.sim_worker.progress_updated.connect(self.progress_bar.setValue)        self.sim_worker.finished_signal.connect(self.action_start_playback)        self.sim_worker.finished.connect(self.on_sim_worker_finished)        self.sim_worker.start()    def on_sim_worker_finished(self):        """        Handles the event when the simulation worker thread actually closes.        If it was canceled early, we need to reset the UI.        """        if not self.sim_worker.is_running:            self.action_measurement_finished()    def action_replay_measurement(self):        """        Replays the last successful measurement without recalculating the data.        """        if self.current_sino_amp is None or self.current_sino_ph is None or self.motion_sequence is None:            QMessageBox.warning(self, "Warning", "No measurement data available to replay.")            return        self.set_ui_enabled(False)        self.action_start_playback(self.current_sino_amp, self.current_sino_ph)    def action_start_playback(self, sino_amp: np.ndarray, sino_ph: np.ndarray):        """        Step 2: Receives the computed sinograms and starts the playback animation.        """        self.btn_start_measurement.setText("Playing measurement...")        self.btn_start_measurement.setEnabled(False) # Block cancellation during playback        self.progress_bar.setVisible(False)                # Save generated frames for later saving/replaying        self.current_sino_amp = sino_amp        self.current_sino_ph = sino_ph        # Initialize playback thread with precalculated data        self.worker = MeasurementWorker(self.motion_sequence, sino_amp, sino_ph)                # Connect signals for 3D update and 2D frame display        self.worker.update_beam_signal.connect(self.viewer_3d.update_beam_transform)        self.worker.update_phantom_signal.connect(self.viewer_3d.update_phantom_transform)        self.worker.update_images_signal.connect(self.update_live_images)        self.worker.finished.connect(self.action_measurement_finished)                self.worker.start()            def action_measurement_finished(self):        """        Step 3: Reset UI state after playback is complete or calculation canceled.        """        self.set_ui_enabled(True)        self.btn_start_measurement.setText("Start Measurement")        self.progress_bar.setVisible(False)        self.action_update_azimuth(self.spin_azimuth.value())        self.viewer_3d.update_phantom_transform(0, 0, 0, 0, 0, 0)            def action_save_sinogram(self):        """        Saves the most recently calculated sinogram data to a .mat file.        """        if self.current_sino_amp is None or self.current_sino_ph is None:            QMessageBox.warning(self, "Warning", "No measurement data to save. Please run a measurement first.")            return                    filepath, _ = QFileDialog.getSaveFileName(            self, "Save Sinogram", "data_io/synthetic_sinogram.mat", "MAT Files (*.mat)"        )                if filepath:            try:                # Pass the dynamically extracted background RI directly                save_sinogram_mat(                    filepath,                     self.current_sino_amp,                     self.current_sino_ph,                     self.current_rayXY,                     self.current_bg_ri                )                QMessageBox.information(self, "Success", f"Sinogram saved successfully to:\n{filepath}")            except Exception as e:                QMessageBox.critical(self, "Error", f"Failed to save file:\n{str(e)}")    def action_save_csv(self):        """        Saves the object motion parameters to a CSV file.        """        if not self.motion_sequence:            QMessageBox.warning(self, "Warning", "No motion data to save. Please run a measurement first.")            return                    filepath, _ = QFileDialog.getSaveFileName(            self, "Save CSV Log", "data_io/motion_log.csv", "CSV Files (*.csv)"        )                if filepath:            try:                save_motion_sequence_csv(filepath, self.motion_sequence)                QMessageBox.information(self, "Success", f"CSV log saved successfully to:\n{filepath}")            except Exception as e:                QMessageBox.critical(self, "Error", f"Failed to save file:\n{str(e)}")            def set_ui_enabled(self, state: bool):        self.btn_load_phantom.setEnabled(state)        self.group_scan_mode.setEnabled(state)        self.group_settings.setEnabled(state)        self.group_accuracy.setEnabled(state)        self.group_kinematics.setEnabled(state)        self.group_noise.setEnabled(state)        self.btn_start_measurement.setEnabled(state)        self.btn_save_sino.setEnabled(state)        self.btn_save_csv.setEnabled(state)                # Only enable replay if we have data and the UI is generally enabled        if state and self.current_sino_amp is not None:            self.btn_replay_measurement.setEnabled(True)        else:            self.btn_replay_measurement.setEnabled(False)    def update_live_images(self, amplitude_data: np.ndarray, phase_data: np.ndarray):        """        Called smoothly by the MeasurementWorker during playback.        """        amp_pixmap = self._convert_numpy_to_pixmap(amplitude_data)        ph_pixmap = self._convert_numpy_to_pixmap(phase_data)                # Scale while keeping aspect ratio and respecting the restricted label size        self.img_amplitude.setPixmap(amp_pixmap.scaled(            self.img_amplitude.size(),             Qt.AspectRatioMode.KeepAspectRatio,             Qt.TransformationMode.SmoothTransformation        ))        self.img_phase.setPixmap(ph_pixmap.scaled(            self.img_phase.size(),             Qt.AspectRatioMode.KeepAspectRatio,             Qt.TransformationMode.SmoothTransformation        ))    def _convert_numpy_to_pixmap(self, arr: np.ndarray) -> QPixmap:        """        Converts 2D numpy array to QPixmap using standard min-max linear normalization.        """        arr_min, arr_max = arr.min(), arr.max()        if arr_max > arr_min:            normalized = (arr - arr_min) / (arr_max - arr_min) * 255.0        else:            normalized = np.zeros_like(arr)                    data = normalized.astype(np.uint8)                # Ensure memory is contiguous before passing to QImage        data = np.ascontiguousarray(data)        height, width = data.shape                qimg = QImage(data.data, width, height, width, QImage.Format.Format_Grayscale8)        return QPixmap.fromImage(qimg)